/**
 * tools/horizon-diag.js — Diagnoses horizon click interception and settings panel
 */
const path = require('path');
const fs   = require('fs');

function findPlaywright() {
    const cacheRoot = path.join(process.env.LOCALAPPDATA || '', 'npm-cache', '_npx');
    if (!fs.existsSync(cacheRoot)) return null;
    for (const entry of fs.readdirSync(cacheRoot)) {
        const candidate = path.join(cacheRoot, entry, 'node_modules', 'playwright');
        if (fs.existsSync(candidate)) return candidate;
    }
    return null;
}

const { chromium } = require(findPlaywright());
const HTML_FILE = path.resolve(__dirname, '..', 'Swimlane_App.html');
const FILE_URL  = 'file:///' + HTML_FILE.replace(/\\/g, '/');

(async () => {
    const browser = await chromium.launch({ headless: true });
    const ctx     = await browser.newContext({ viewport: { width: 1280, height: 900 } });

    // seed one future milestone
    const tomorrow = new Date(); tomorrow.setDate(tomorrow.getDate() + 1);
    const futureDateStr = tomorrow.toISOString().split('T')[0];
    const seedState = {
        version: 14,
        lanes:   [{ id: 'diag-lane', title: 'Diag', minimized: false, color: '#6366f1' }],
        habits: [], notes: [], projects: [], habitChecks: {}, diary: {}, focus: {},
        items: [{ id: 'diag-item', laneId: 'diag-lane', dateStr: futureDateStr,
                  type: 'type-milestone', text: 'Click me', isDone: false }],
        settings: { theme: 'dotted', horizonMode: 'all', habitMode: 'streak',
                    showAchievements: false, showHorizon: false, habitsMin: false, diaryMin: false }
    };

    const seedPage = await ctx.newPage();
    await seedPage.goto(FILE_URL);
    await seedPage.waitForTimeout(600);
    await seedPage.evaluate(async (s) => {
        await new Promise(resolve => {
            const req = indexedDB.open('SwimlaneDB_V14', 1);
            req.onsuccess = e => {
                const db = e.target.result;
                const tx = db.transaction('state', 'readwrite');
                tx.objectStore('state').put(s, 'appData');
                tx.oncomplete = () => { db.close(); resolve(); };
            };
        });
    }, seedState);
    await seedPage.evaluate((seed) => {
        const orig = IDBObjectStore.prototype.put;
        IDBObjectStore.prototype.put = function(v, k) { IDBObjectStore.prototype.put = orig; return orig.call(this, seed, k); };
    }, seedState);
    await seedPage.goto('about:blank');
    await seedPage.close();

    const page = await ctx.newPage();
    await page.addInitScript(() => localStorage.setItem('swimlane_onboarded', 'true'));
    await page.goto(FILE_URL);
    await page.waitForTimeout(1500);
    await page.click('[data-action="toggleHorizon"]');
    await page.waitForTimeout(600);

    const diag = await page.evaluate(() => {
        const input = document.querySelector('.hz-item .index-text');
        if (!input) return { error: 'no .hz-item .index-text found' };

        const inputRect = input.getBoundingClientRect();
        const cx = inputRect.left + inputRect.width / 2;
        const cy = inputRect.top  + inputRect.height / 2;
        const topEl = document.elementFromPoint(cx, cy);

        // What's inside the header-track and what are their rects?
        const headerTrack = document.querySelector('.header-track');
        const headerTrackRect = headerTrack?.getBoundingClientRect();
        const trackChildren = headerTrack ? Array.from(headerTrack.children).map(c => {
            const r = c.getBoundingClientRect();
            return { tag: c.tagName, cls: c.className?.toString().trim().split(/\s+/).slice(0,3).join(' '),
                     top: r.top, bottom: r.bottom, height: r.height };
        }) : [];

        // Where is the settings panel in the DOM?
        const settingsPanel = document.querySelector('.settings-panel');
        const settingsPanelInfo = settingsPanel ? {
            parentTag: settingsPanel.parentElement?.tagName,
            parentId:  settingsPanel.parentElement?.id || null,
            parentCls: settingsPanel.parentElement?.className?.toString().trim().split(/\s+/).slice(0,3).join(' '),
            computedPosition: getComputedStyle(settingsPanel).position,
            computedZIndex:   getComputedStyle(settingsPanel).zIndex,
            computedDisplay:  getComputedStyle(settingsPanel).display,
        } : { error: 'not found' };

        // z-index of key elements
        const zCheck = {};
        ['journal-header', 'journal-horizon', 'journal-container'].forEach(id => {
            const el = document.getElementById(id);
            if (el) zCheck[id] = { zi: getComputedStyle(el).zIndex, pos: getComputedStyle(el).position };
        });

        return {
            inputRect: { top: inputRect.top, bottom: inputRect.bottom },
            clickPoint: { x: cx, y: cy },
            topEl: topEl ? { tag: topEl.tagName, cls: topEl.className?.toString().trim().split(/\s+/).slice(0,3).join(' '), sameAsInput: topEl === input } : null,
            headerTrackRect: headerTrackRect ? { top: headerTrackRect.top, bottom: headerTrackRect.bottom } : null,
            trackChildren,
            settingsPanelInfo,
            zCheck,
        };
    });

    console.log('\n── Horizon diagnostic ────────────────────────────────────────');
    console.log(JSON.stringify(diag, null, 2));

    console.log('\n── Real click attempt ────────────────────────────────────────');
    try {
        await page.click('.hz-item .index-text', { timeout: 3000 });
        console.log('✔  click succeeded');
    } catch (e) {
        console.log('✖  click FAILED:', e.message.split('\n')[0]);
    }

    await page.screenshot({ path: path.join(__dirname, 'horizon-diag.png') });
    console.log('Screenshot: tools/horizon-diag.png\n');
    await browser.close();
})();

