file.content:
.journal-header > div { height: 132px; max-height: 132px; box-sizing: border-box; }

.header-track { 
    width: 100%; padding: 0 10px 8px 10px; 
    position: relative; display: flex; flex-direction: column; align-items: center; justify-content: flex-end;
    min-width: 0; overflow-x: hidden;
}

.header-track::after {
    content: ''; position: absolute; bottom: 0; left: 6px; right: 6px; height: 4px;
    border-radius: 2px 2px 0 0; background: var(--lc); opacity: 0.5; transition: opacity 0.2s;
}
.header-track:hover::after { opacity: 1; }

.track-title {
    line-height: 1; border: none; background: transparent; 
    font-family: var(--font-ui); font-size: 36px; font-weight: bold; color: #0f172a;
    text-align: center; outline: none; width: 100%; display: block; margin-bottom: 2px;
}

.track-controls { position: absolute; top: 10px; right: 10px; display: flex; gap: 5px; opacity: 0; transition: opacity 0.2s; z-index: 10; }
.header-track:hover .track-controls { opacity: 1; }
@media (hover: none) { .track-controls { opacity: 1; } } 

.ctrl-btn {
    cursor: pointer; font-family: sans-serif; font-size: 16px; font-weight: bold; background: #fff; border-radius: 4px; width: 24px; height: 24px; 
    display: flex; align-items: center; justify-content: center; border: 1px solid #cbd5e1; color: #64748b;
}
.ctrl-btn.del { color: #ef4444; border-color: #fca5a5; border-radius: 50%; font-size: 18px;}

