1699	            horizonData() {
1700	                if(!state.settings.showHorizon) return;
1701	                const sysToday = Utils.todayStr;
1702	
1703	                state.lanes.forEach(lane => {
1704	                    const bin = document.getElementById(`overdue-bin-${lane.id}`);
1705	                    const sec = document.getElementById(`overdue-sec-${lane.id}`);
1706	                    if(bin && sec) {
1707	                        bin.innerHTML = '';
1708	                        const overdue = state.items.filter(i => i.laneId === lane.id && !i.isDone && i.dateStr && i.dateStr < sysToday);
1709	                        if (overdue.length > 0) {
1710	                            overdue.forEach(itemData => {
1711	                                const itemEl = document.createElement('div');
1712	                                itemEl.className = `item sl-${lane.id} ${itemData.type} is-clone is-overdue`;
1713	                                itemEl.dataset.id = itemData.id;
1714	                                itemEl.innerHTML = Render.itemHTML(itemData, { showProjectTag: true, isReadonly: true });
1715	                                bin.appendChild(itemEl);
1716	                            });
1717	                            sec.style.display = 'block';
1718	                        } else { sec.style.display = 'none'; }
1719	                    }
1720	
1721	                    const container = document.getElementById(`hz-${lane.id}`);
