updateTaskText(id, text) { 
    const item = state.items.find(x => x.id === id); 
    if(item) {
        this.mutate(() => { item.text = text; }, 'silentSave'); 
        document.querySelectorAll(`.item[data-id="${id}"] .text-input-readonly`).forEach(el => el.textContent = text);
        document.querySelectorAll(`.index-list li[data-id="${id}"] .index-text`).forEach(el => { if (el.tagName === 'INPUT') el.value = text; else el.textContent = text; });
    }
},
updateTaskNote(id, noteHTML) {
    const item = state.items.find(x => x.id === id);
    if (item) {
        this.mutate(() => { item.note = noteHTML; }, 'silentSave');
        const toggle = document.querySelector(`.item[data-id="${id}"] .task-note-toggle`);
        if(toggle) toggle.classList.toggle('has-note', noteHTML.trim() !== '');
    }

