.onboarding-modal {
    background: #fdfbf7; width: 100%; max-width: 600px; border-radius: 12px; box-shadow: 0 25px 50px -12px rgba(0,0,0,0.25);
    display: flex; flex-direction: column; align-items: flex-start; padding: 40px; border: 2px solid #cbd5e1; z-index: 9999;
}
.onboarding-modal h1 { font-family: var(--font-ui); font-size: 56px; color: #0f172a; margin: 0 0 10px 0; line-height: 1; }
.onboarding-modal p.subtitle { font-family: sans-serif; font-size: 16px; color: #475569; margin-top: 0; margin-bottom: 30px; font-weight: 500;}
.onboarding-modal ul { font-family: sans-serif; font-size: 15px; color: #475569; line-height: 1.6; padding-left: 20px; margin-bottom: 40px; width: 100%; text-align: left;}
.onboarding-modal ul li { margin-bottom: 12px; }

.focus-stats-modal { background: #fff; width: 100%; max-width: 400px; border-radius: 12px; padding: 30px; font-family: sans-serif; display: flex; flex-direction: column; gap: 15px; box-shadow: 0 25px 50px -12px rgba(0,0,0,0.25);}
.focus-stat-title { font-size: 14px; font-weight: bold; color: #94a3b8; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 5px; border-bottom: 1px solid #e2e8f0; padding-bottom: 5px;}
.focus-stat-row { display: flex; justify-content: space-between; align-items: center; font-size: 16px; color: #1e293b; font-weight: 600;}
.focus-score { font-size: 48px; font-family: var(--font-ui); color: #3b82f6; text-align: center; font-weight: bold; margin: 10px 0;}

.search-modal { background: #fff; width: 100%; max-width: 600px; border-radius: 12px; box-shadow: 0 25px 50px -12px rgba(0,0,0,0.25); display: flex; flex-direction: column; overflow: hidden; font-family: sans-serif; }
.search-input { width: 100%; border: none; padding: 20px 24px; font-size: 18px; outline: none; border-bottom: 1px solid #e2e8f0; color: #0f172a; }
.search-results { max-height: 400px; overflow-y: auto; list-style: none; margin: 0; padding: 0; }
.search-item { padding: 12px 24px; border-bottom: 1px solid #f1f5f9; cursor: pointer; display: flex; flex-direction: column; gap: 4px; }

